import {
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';
import type { ClipboardEntry } from '../../data/clipboard_data';
import { MOCK_CLIPBOARD_ENTRIES } from '../../data/clipboard_data';
import { useAlert } from '../../hooks/use_alert';
import { useHUD } from '../../hooks/use_hud';
import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
import { useNavigation } from '../../hooks/use_navigation';
import { formatRelativeDate } from '../../utils/format_date';
import { isRecord, isStringArray, storageGet, storageSet } from '../../utils/storage';
import { ActionPanel } from '../action_panel/action_panel';
import type { DropdownSection } from '../action_panel/actions_dropdown';
import { Alert } from '../alert/alert';
import { EmptyState } from '../empty_state/empty_state';
import { HUDContainer } from '../hud/hud_container';
import { Kbd } from '../kbd/kbd';
import { List, ListItem, ListSection } from '../list';
import { SearchBar } from '../search_bar/search_bar';
import type { SearchDropdownSection } from '../search_bar/search_dropdown';
import { SearchDropdown } from '../search_bar/search_dropdown';
import './clipboard_history_view.scss';

function ClipboardHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <rect
        x="4"
        y="2"
        width="8"
        height="12"
        rx="1.5"
        stroke="currentColor"
        strokeWidth="1.5"
      />
      <path
        d="M6 2.5H10"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

function PinIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path
        d="M10 1L14 5L11 8V11.5L8.5 14L8 9.5L3.5 9L6 6.5L3 3.5L6 1L8.5 3.5L10 1Z"
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinecap="round"
        strokeLinejoin="round"
        fill="none"
      />
    </svg>
  );
}

function SearchEmptyIcon() {
  return (
    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
      <line
        x1="30"
        y1="30"
        x2="42"
        y2="42"
        stroke="currentColor"
        strokeWidth="3"
        strokeLinecap="round"
      />
    </svg>
  );
}

function ImageIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect
        x="2"
        y="3"
        width="16"
        height="14"
        rx="2"
        stroke="currentColor"
        strokeWidth="1.5"
      />
      <circle cx="7" cy="8" r="1.5" fill="currentColor" />
      <path
        d="M2 14L7 10L10 13L13 9L18 14"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ColorDot({ color }: { color: string }) {
  return (
    <span
      className="clipboard-history__color-dot"
      style={{ backgroundColor: color }}
    />
  );
}

function truncateContent(content: string, maxLength: number): string {
  if (content.length <= maxLength) return content;
  return content.slice(0, maxLength) + '\u2026';
}

function renderClipboardIcon(entry: ClipboardEntry): ReactNode {
  if (entry.contentType === 'color') {
    return <ColorDot color={entry.content} />;
  }
  if (entry.contentType === 'image') {
    return <ImageIcon />;
  }
  return entry.sourceIcon;
}

const PINNED_KEY = 'clipboard-pinned';
const DELETED_KEY = 'clipboard-deleted';

interface ClipboardMutations {
  pinned: Set<string>;
  deleted: Set<string>;
}

function loadMutations(): ClipboardMutations {
  const pinned = storageGet(PINNED_KEY, isStringArray) ?? [];
  const deleted = storageGet(DELETED_KEY, isStringArray) ?? [];
  return {
    pinned: new Set(pinned),
    deleted: new Set(deleted),
  };
}

function isClipboardPinRecord(value: unknown): value is Record<string, boolean> {
  if (!isRecord(value)) return false;
  return Object.values(value).every(v => typeof v === 'boolean');
}

function loadInitialEntries(): ClipboardEntry[] {
  const mutations = loadMutations();
  return MOCK_CLIPBOARD_ENTRIES
    .filter(e => !mutations.deleted.has(e.id))
    .map(e => ({
      ...e,
      pinned: mutations.pinned.has(e.id) ? true :
        (!mutations.pinned.has(e.id) && MOCK_CLIPBOARD_ENTRIES.find(m => m.id === e.id)?.pinned === true && !isClipboardPinRecord(null))
          ? e.pinned : e.pinned,
    }));
}

const FILTER_SECTIONS: SearchDropdownSection[] = [
  {
    options: [
      {
        label: 'All',
        value: 'all',
      },
