    if (!selectedEntry) return;
    setActionsOpen(false);
    showHUD({
      icon: <ClipboardHUDIcon />,
      title: 'Pasted',
    });
  }, [
    selectedEntry,
    showHUD,
  ]);

  const handleTogglePin = useCallback(() => {
    if (!selectedEntry) return;
    setActionsOpen(false);
    const entryId = selectedEntry.id;
    const wasPinned = selectedEntry.pinned;
    setEntries(prev =>
      prev.map(e =>
        e.id === entryId
          ? {
              ...e,
              pinned: !e.pinned,
            }
          : e));
