                keys={[
                  '⌘',
                  'C',
                ]}
              />
            ),
            onClick: handleCopy,
          },
        ],
      },
      {
        title: 'Organize',
        actions: [
          {
            label: selectedEntry?.pinned ? 'Unpin' : 'Pin',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  '⇧',
                  'P',
                ]}
              />
            ),
            onClick: handleTogglePin,
          },
        ],
      },
      {
        title: 'Danger Zone',
        actions: [
          {
            label: 'Delete',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  '⌫',
