              />
            ),
            onClick: handleDelete,
          },
        ],
      },
    ],
    [
      selectedEntry?.pinned,
      handlePaste,
      handleCopy,
      handleTogglePin,
      handleDelete,
    ],
  );

  const activeDescendantId =
