const SNIPPETS_KEY = 'snippets';

interface StoredSnippet {
  id: string;
  name: string;
  keyword: string;
  content: string;
  category: string;
  tags: {
    text: string;
    color?: string;
  }[];
  createdAt: string;
}

function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
  if (!Array.isArray(value)) return false;
  return value.every(
    v =>
      typeof v === 'object' &&
      v !== null &&
      typeof (v as StoredSnippet).id === 'string' &&
      typeof (v as StoredSnippet).name === 'string' &&
      typeof (v as StoredSnippet).createdAt === 'string',
  );
}

function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
  return entries.map(e => ({
    ...e,
    createdAt: e.createdAt.toISOString(),
  }));
}

const TAG_COLORS = new Set<string>([
  'blue',
  'green',
  'orange',
  'red',
  'purple',
  'yellow',
]);

function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
  return stored.map(s => ({
    ...s,
    category: isSnippetCategory(s.category) ? s.category : 'general',
    tags: s.tags.map(t => ({
      text: t.text,
      color:
        t.color && TAG_COLORS.has(t.color) ? (t.color as TagColor) : undefined,
    })),
    createdAt: new Date(s.createdAt),
  }));
}

function loadSnippets(): SnippetEntry[] {
  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
  if (stored) return deserializeEntries(stored);

